1729   if (PHINode *UsePhi = dyn_cast<PHINode>(DU.NarrowUse)) {
1730     if (LI->getLoopFor(UsePhi->getParent()) != L) {
1731       // For LCSSA phis, sink the truncate outside the loop.
1732       // After SimplifyCFG most loop exit targets have a single predecessor.
1733       // Otherwise fall back to a truncate within the loop.
1734       if (UsePhi->getNumOperands() != 1)
1735         truncateIVUse(DU, DT, LI);
