1747         BasicBlock *WidePhiBB = WidePhi->getParent();
1748         IRBuilder<> Builder(WidePhiBB, WidePhiBB->getFirstInsertionPt());
1749         Value *Trunc = Builder.CreateTrunc(WidePhi, DU.NarrowDef->getType());
